ody ol {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #475569;\n            line-height: 1.8;\n            margin: 0 0 24px;\n            padding-left: 24px;\n        }\n        .article-body li {\n            margin-bottom: 8px;\n        }\n        .article-body strong {\n            color: #000864;\n            font-weight: 600;\n        }\n\n        /* Lead paragraph */\n        .article-lead {\n            font-size: 20px !important;\n            color: #334155 !important;\n            line-height: 1.7 !important;\n            border-left: 3px solid #00AFF0;\n            padding-left: 24px;\n            margin-bottom: 40px !important;\n        }\n\n        /* Pull quote */\n        .article-pullquote {\n            border-left: 4px solid #00AFF0;\n            padding: 24px 32px;\n            margin: 40px 0;\n            background: transparent;\n        }\n        .article-pullquote p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px !important;\n            font-style: italic;\n            color: #000864 !important;\n            line-height: 1.6 !important;\n            margin: 0 !important;\n        }\n\n        /* Data callout */\n        .article-data-callout {\n            background: linear-gradient(135deg, #000864 0%, #1e3a5f 100%);\n            border-radius: 16px;\n            padding: 40px;\n            margin: 40px 0;\n            display: grid;\n            grid-template-columns: 1fr auto 1fr;\n            align-items: center;\n            gap: 24px;\n            text-align: center;\n        }\n        .article-data-callout-item {\n            display: flex;\n            flex-direction: column;\n            gap: 8px;\n        }\n        .article-data-callout-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 13px;\n            font-weight: 500;\n            color: rgba(255,255,255,0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        }\n        .article-data-callout-value {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: clamp(28px, 4vw, 40px);\n            font-weight: 500;\n            color: #ffffff;\n            line-height: 1;\n        }\n        .article-data-callout-value.highlight {\n            color: #00AFF0;\n        }\n        .article-data-callout-arrow {\n            font-size: 32px;\n            color: rgba(255,255,255,0.75);\n        }\n\n        /* Highlight box */\n        .article-highlight {\n            background: #EBF5FF;\n            border-left: 4px solid #00AFF0;\n            border-radius: 0 12px 12px 0;\n            padding: 24px 32px;\n            margin: 40px 0;\n        }\n        .article-highlight p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px !important;\n            color: #1e3a5f !important;\n            line-height: 1.7 !important;\n            margin: 0 !important;\n        }\n        .article-highlight strong {\n            color: #000864;\n        }\n\n        /* Scenario box */\n        .article-scenario {\n            background: #F5F7FA;\n            border-radius: 16px;\n            padding: 32px;\n            margin: 40px 0;\n        }\n        .article-scenario-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            font-weight: 600;\n            color: #0369a1;\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n            margin-bottom: 16px;\n        }\n        .article-scenario ol {\n            margin: 0 !important;\n            padding-left: 20px;\n        }\n        .article-scenario li {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px;\n            color: #475569;\n            line-height: 1.7;\n            margin-bottom: 8px;\n        }\n\n        /* ===== Related Articles ===== */\n        .related-section {\n    