osition: relative;\n            overflow: hidden;\n        }\n        .article-cta::before {\n            content: \'\';\n            position: absolute;\n            top: -50%;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 800px;\n            height: 800px;\n            background: radial-gradient(circle, rgba(0, 175, 240, 0.1) 0%, transparent 60%);\n            pointer-events: none;\n        }\n        .article-cta-inner {\n            max-width: 700px;\n            margin: 0 auto;\n            text-align: center;\n            position: relative;\n            z-index: 1;\n        }\n        .article-cta-icon {\n            width: 64px;\n            height: 64px;\n            background: rgba(0, 175, 240, 0.15);\n            border-radius: 16px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin: 0 auto 24px;\n        }\n        .article-cta-icon svg {\n            width: 32px;\n            height: 32px;\n            stroke: #00AFF0;\n            stroke-width: 1.5;\n            fill: none;\n        }\n        .article-cta h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(28px, 4vw, 36px);\n            font-weight: 700;\n            color: #ffffff;\n            margin: 0 0 16px;\n            line-height: 1.2;\n        }\n        .article-cta p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: rgba(255,255,255,0.75);\n            line-height: 1.6;\n            margin: 0 0 32px;\n        }\n        .article-cta .cta-btn {\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            font-weight: 600;\n            color: #ffffff;\n            background: linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);\n            padding: 16px 36px;\n            border-radius: 10px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n            box-shadow: 0 4px 20px rgba(0, 175, 240, 0.35);\n        }\n        .article-cta .cta-btn:hover {\n            transform: translateY(-2px);\n            box-shadow: 0 8px 30px rgba(0, 175, 240, 0.45);\n        }\n        .article-cta .cta-btn svg {\n            width: 18px;\n            height: 18px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n            transition: transform 0.3s ease;\n        }\n        .article-cta .cta-btn:hover svg {\n            transform: translateX(3px);\n        }\n\n        /* Scroll animations: .fade-in handled by shared styles.css */\n\n        /* ===== Responsive ===== */\n        @media (max-width: 768px) {\n            .article-hero {\n                padding: 130px 20px 60px;\n            }\n            .article-hero h1 {\n                font-size: 28px;\n            }\n            .article-body {\n                padding: 40px 20px 60px;\n            }\n            .article-body h2 {\n                font-size: 24px;\n            }\n            .article-data-callout {\n                grid-template-columns: 1fr;\n                gap: 16px;\n                padding: 32px 24px;\n            }\n            .article-data-callout-arrow {\n                transform: rotate(90deg);\n            }\n            .related-grid {\n                grid-template-columns: 1fr;\n                gap: 16px;\n            }\n            .article-pullquote {\n                padding: 20px 24px;\n            }\n            .article-highlight {\n                padding: 20px 24px;\n            }\n            .article-scenario {\n                padding: 24px;\n            }\n        }\n\n        @media (prefers-reduced-motion: reduce) {\n            .article-back,\n            .related-card,\n            .related-card-arrow,\n            .article-cta .cta-btn,\n            .article-cta .cta-btn