INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100766, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === BLOG POST: LRP VS MRP: WHY YOUR PRODUCTION PLANNING TAKES HOURS INSTEAD OF MINUTES === */\n/* Divi section-level overrides — reset padding/margin/width on all sections */\n.et_pb_section { padding: 0 !important; min-height: auto !important; margin: 0 !important; text-align: start !important; }\n.et_pb_section .et_pb_row { max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important; }\n.et_pb_section .et_pb_column { padding: 0 !important; }\n/* Font smoothing reset */\n.et_pb_section, .et_pb_section * { -webkit-font-smoothing: auto !important; -moz-osx-font-smoothing: auto !important; }\n/* Divi p padding reset */\n.et_pb_section p { padding-bottom: 0 !important; }\n/* Override blog-body h2/h3 line-height from Divi defaults */\n.et_pb_section .blog-body h2, .et_pb_section .article-body h2 { line-height: 1.3 !important; }\n.et_pb_section .blog-body h3, .et_pb_section .article-body h3 { line-height: 1.35 !important; }\n/* Ensure fade-in elements are visible (no JS scroll observer in Divi) */\n.fade-in { opacity: 1 !important; transform: none !important; }\n/* Resolve CSS vars used in styles.css */\n:root { --dw-blue-text: #0369a1; --dw-gray-light: #F5F7FA; --dw-navy: #000864; }\n\n\n\n/* ===== Article Hero ===== */\n        .article-hero {\n            background: linear-gradient(135deg, #1a2332 0%, #000864 50%, #1e3a5f 100%);\n            padding: 160px 24px 80px;\n            position: relative;\n            overflow: hidden;\n        }\n        .article-hero::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n        .article-hero::after {\n            content: \'\';\n            position: absolute;\n            top: -50%;\n            right: -20%;\n            width: 600px;\n            height: 600px;\n            background: radial-gradient(circle, rgba(0, 175, 240, 0.08) 0%, transparent 70%);\n            pointer-events: none;\n        }\n        .article-hero-inner {\n            max-width: 800px;\n            margin: 0 auto;\n            position: relative;\n            z-index: 1;\n        }\n        .article-back {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: rgba(255,255,255,0.75);\n            text-decoration: none;\n            margin-bottom: 32px;\n            transition: color 0.3s ease;\n        }\n        .article-back:hover {\n            color: #0369a1;\n        }\n        .article-back svg {\n            width: 16px;\n            height: 16px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n        }\n        .article-category {\n            display: inline-block;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            letter-spacing: 0.1em;\n            text-transform: uppercase;\n            color: #ffffff;\n            background: #00AFF0;\n            padding: 6px 16px;\n            border-radius: 4px;\n            margin-bottom: 24px;\n        }\n        .article-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(32px, 5vw, 48px);\n            font-weight: 700;\n            color: #ffffff;\n            line-height: 1.15;\n            margin: 0 0 24px;\n            letter-spacing: -0.02em;\n        }\n        .article-meta {\n            display: flex;\n            align-items: center;\n            gap: 16px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: rgba(255,255,255,0.75);\n        }\n        .article-meta-divider {\n            width: 4px;\n            height: 4px;\n            background: rgba(255,255,255,0.3);\n            border-radius: 50%;\n        }\n\n        /* ===== Article Body ===== */\n        .article-body {\n            max-width: 800px;\n            margin: 0 auto;\n            padding: 64px 24px 80px;\n        }\n        .article-body p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #475569;\n            line-height: 1.8;\n            margin: 0 0 24px;\n        }\n        .article-body h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 28px;\n            font-weight: 700;\n            color: #000864;\n            margin: 56px 0 20px;\n            line-height: 1.3;\n            letter-spacing: -0.01em;\n        }\n        .article-body h3 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 22px;\n            font-weight: 600;\n            color: #000864;\n            margin: 40px 0 16px;\n            line-height: 1.3;\n        }\n        .article-body ul, .article-body ol {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #475569;\n            line-height: 1.8;\n            margin: 0 0 24px;\n            padding-left: 24px;\n        }\n        .article-body li {\n            margin-bottom: 8px;\n        }\n        .article-body strong {\n            color: #000864;\n            font-weight: 600;\n        }\n\n        /* Lead paragraph */\n        .article-lead {\n            font-size: 20px !important;\n            color: #334155 !important;\n            line-height: 1.7 !important;\n            border-left: 3px solid #00AFF0;\n            padding-left: 24px;\n            margin-bottom: 40px !important;\n        }\n\n        /* Pull quote */\n        .article-pullquote {\n            border-left: 4px solid #00AFF0;\n            padding: 24px 32px;\n            margin: 40px 0;\n            background: transparent;\n        }\n        .article-pullquote p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px !important;\n            font-style: italic;\n            color: #000864 !important;\n            line-height: 1.6 !important;\n            margin: 0 !important;\n        }\n\n        /* Data callout */\n        .article-data-callout {\n            background: linear-gradient(135deg, #000864 0%, #1e3a5f 100%);\n            border-radius: 16px;\n            padding: 40px;\n            margin: 40px 0;\n            display: grid;\n            grid-template-columns: 1fr auto 1fr;\n            align-items: center;\n            gap: 24px;\n            text-align: center;\n        }\n        .article-data-callout-item {\n            display: flex;\n            flex-direction: column;\n            gap: 8px;\n        }\n        .article-data-callout-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 13px;\n            font-weight: 500;\n            color: rgba(255,255,255,0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        }\n        .article-data-callout-value {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: clamp(28px, 4vw, 40px);\n            font-weight: 500;\n            color: #ffffff;\n            line-height: 1;\n        }\n        .article-data-callout-value.highlight {\n            color: #00AFF0;\n        }\n        .article-data-callout-arrow {\n            font-size: 32px;\n            color: rgba(255,255,255,0.75);\n        }\n\n        /* Highlight box */\n        .article-highlight {\n            background: #EBF5FF;\n            border-left: 4px solid #00AFF0;\n            border-radius: 0 12px 12px 0;\n            padding: 24px 32px;\n            margin: 40px 0;\n        }\n        .article-highlight p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px !important;\n            color: #1e3a5f !important;\n            line-height: 1.7 !important;\n            margin: 0 !important;\n        }\n        .article-highlight strong {\n            color: #000864;\n        }\n\n        /* Scenario box */\n        .article-scenario {\n            background: #F5F7FA;\n            border-radius: 16px;\n            padding: 32px;\n            margin: 40px 0;\n        }\n        .article-scenario-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            font-weight: 600;\n            color: #0369a1;\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n            margin-bottom: 16px;\n        }\n        .article-scenario ol {\n            margin: 0 !important;\n            padding-left: 20px;\n        }\n        .article-scenario li {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px;\n            color: #475569;\n            line-height: 1.7;\n            margin-bottom: 8px;\n        }\n\n        /* ===== Related Articles ===== */\n        .related-section {\n            background: #F5F7FA;\n            padding: 80px 24px;\n        }\n        .related-inner {\n            max-width: 1000px;\n            margin: 0 auto;\n        }\n        .related-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            color: #0369a1;\n            letter-spacing: 2px;\n            text-transform: uppercase;\n            margin-bottom: 12px;\n        }\n        .related-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 32px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 40px;\n        }\n        .related-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 24px;\n        }\n        .related-card {\n            background: #ffffff;\n            border-radius: 16px;\n            overflow: hidden;\n            box-shadow: 0 2px 12px rgba(0,0,0,0.06);\n            transition: all 0.3s ease;\n            text-decoration: none;\n            display: flex;\n            flex-direction: column;\n        }\n        .related-card:hover {\n            transform: translateY(-4px);\n            box-shadow: 0 12px 32px rgba(0,0,0,0.1);\n        }\n        .related-card-image {\n            height: 160px;\n            background: linear-gradient(135deg, #000864, #1e3a5f);\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            position: relative;\n            overflow: hidden;\n        }\n        .related-card-image::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'40\' height=\'40\' viewBox=\'0 0 40 40\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.04\'%3E%3Cpath d=\'M20 0l20 20-20 20L0 20z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n        }\n        .related-card-image svg {\n            width: 56px;\n            height: 56px;\n            stroke: rgba(0, 175, 240, 0.5);\n            stroke-width: 1.5;\n            fill: none;\n            position: relative;\n            z-index: 1;\n        }\n        .related-card-body {\n            padding: 24px;\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .related-card-category {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            letter-spacing: 0.1em;\n            text-transform: uppercase;\n            margin-bottom: 8px;\n        }\n        .related-card-category.cat-compliance { color: #16a34a; }\n        .related-card-category.cat-cost { color: #92400e; }\n        .related-card-category.cat-planning { color: #0369a1; }\n        .related-card-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            font-weight: 600;\n            color: #000864;\n            line-height: 1.35;\n            margin: 0;\n            flex: 1;\n        }\n        .related-card-arrow {\n            display: inline-flex;\n            align-items: center;\n            gap: 6px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            font-weight: 600;\n            color: #0369a1;\n            margin-top: 16px;\n            transition: gap 0.3s ease;\n        }\n        .related-card:hover .related-card-arrow {\n            gap: 10px;\n        }\n        .related-card-arrow svg {\n            width: 16px;\n            height: 16px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n        }\n\n        /* ===== CTA Section ===== */\n        .article-cta {\n            background: linear-gradient(135deg, #000864 0%, #1e3a5f 50%, #0f172a 100%);\n            padding: 80px 24px;\n            position: relative;\n            overflow: hidden;\n        }\n        .article-cta::before {\n            content: \'\';\n            position: absolute;\n            top: -50%;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 800px;\n            height: 800px;\n            background: radial-gradient(circle, rgba(0, 175, 240, 0.1) 0%, transparent 60%);\n            pointer-events: none;\n        }\n        .article-cta-inner {\n            max-width: 700px;\n            margin: 0 auto;\n            text-align: center;\n            position: relative;\n            z-index: 1;\n        }\n        .article-cta-icon {\n            width: 64px;\n            height: 64px;\n            background: rgba(0, 175, 240, 0.15);\n            border-radius: 16px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin: 0 auto 24px;\n        }\n        .article-cta-icon svg {\n            width: 32px;\n            height: 32px;\n            stroke: #00AFF0;\n            stroke-width: 1.5;\n            fill: none;\n        }\n        .article-cta h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(28px, 4vw, 36px);\n            font-weight: 700;\n            color: #ffffff;\n            margin: 0 0 16px;\n            line-height: 1.2;\n        }\n        .article-cta p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: rgba(255,255,255,0.75);\n            line-height: 1.6;\n            margin: 0 0 32px;\n        }\n        .article-cta .cta-btn {\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            font-weight: 600;\n            color: #ffffff;\n            background: linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);\n            padding: 16px 36px;\n            border-radius: 10px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n            box-shadow: 0 4px 20px rgba(0, 175, 240, 0.35);\n        }\n        .article-cta .cta-btn:hover {\n            transform: translateY(-2px);\n            box-shadow: 0 8px 30px rgba(0, 175, 240, 0.45);\n        }\n        .article-cta .cta-btn svg {\n            width: 18px;\n            height: 18px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n            transition: transform 0.3s ease;\n        }\n        .article-cta .cta-btn:hover svg {\n            transform: translateX(3px);\n        }\n\n        /* Scroll animations: .fade-in handled by shared styles.css */\n\n        /* ===== Responsive ===== */\n        @media (max-width: 768px) {\n            .article-hero {\n                padding: 130px 20px 60px;\n            }\n            .article-hero h1 {\n                font-size: 28px;\n            }\n            .article-body {\n                padding: 40px 20px 60px;\n            }\n            .article-body h2 {\n                font-size: 24px;\n            }\n            .article-data-callout {\n                grid-template-columns: 1fr;\n                gap: 16px;\n                padding: 32px 24px;\n            }\n            .article-data-callout-arrow {\n                transform: rotate(90deg);\n            }\n            .related-grid {\n                grid-template-columns: 1fr;\n                gap: 16px;\n            }\n            .article-pullquote {\n                padding: 20px 24px;\n            }\n            .article-highlight {\n                padding: 20px 24px;\n            }\n            .article-scenario {\n                padding: 24px;\n            }\n        }\n\n        @media (prefers-reduced-motion: reduce) {\n            .article-back,\n            .related-card,\n            .related-card-arrow,\n            .article-cta .cta-btn,\n            .article-cta .cta-btn svg {\n                transition: none !important;\n            }\n            .related-card:hover,\n            .article-cta .cta-btn:hover {\n                transform: none !important;\n            }\n            .article-cta .cta-btn:hover svg {\n                transform: none !important;\n            }\n            .fade-in,\n            .dw-d-bg,\n            .dw-wave-circles {\n                animation: none !important;\n                opacity: 1 !important;\n            }\n        }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

-- Step 3: Ensure Divi 5 builder flags
DELETE FROM wp_postmeta WHERE post_id = 100766 AND meta_key = '_et_pb_use_builder';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100766, '_et_pb_use_builder', 'on');
DELETE FROM wp_postmeta WHERE post_id = 100766 AND meta_key = '_et_pb_use_divi_5';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100766, '_et_pb_use_divi_5', 'on');
DELETE FROM wp_postmeta WHERE post_id = 100766 AND meta_key = '_et_pb_page_layout';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100766, '_et_pb_page_layout', 'et_full_width_page');

-- Step 4: Flush Divi cache
DELETE FROM wp_postmeta WHERE post_id = 100766 AND meta_key LIKE '_divi_dynamic_assets%';
DELETE FROM wp_postmeta WHERE post_id = 100766 AND meta_key LIKE '_divi_%canvas%';
